/**
 * OKKI 交易 → 销售订单 同步脚本 v2
 * 针对 Vue 虚拟滚动列表结构重写选择器
 * 用法：node scripts/sync_orders.js
 */
const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const CDP_URL = 'http://localhost:9222';
const DATA_DIR = path.join(__dirname, '..', 'data');

function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }

async function main() {
  let browser, page;

  // CDP 连接
  let useCdp = false;
  try {
    const http = require('http');
    const cdpOk = await new Promise(r => {
      http.get('http://127.0.0.1:9222/json/version', res => r(true)).on('error', () => r(false));
    });
    if (cdpOk) {
      browser = await chromium.connectOverCDP(CDP_URL);
      const pages = browser.contexts()[0].pages();
      page = pages[0];
      useCdp = true;
      log('CDP 已连接');
    }
  } catch (e) {}

  if (!useCdp) {
    log('启动 Chrome...');
    browser = await chromium.launchPersistentContext(PROFILE, {
      channel: 'chrome', headless: false,
      viewport: { width: 1440, height: 900 },
      args: ['--remote-debugging-port=9222'],
    });
    page = await browser.newPage();
  }

  // 导航到订单页
  log('导航到销售订单页...');
  await page.goto('https://crm.xiaoman.cn/order', { waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
  await new Promise(r => setTimeout(r, 2000));

  // 等登录
  if (page.url().includes('login')) {
    log('请登录 OKKI...');
    const startTime = Date.now();
    while (page.url().includes('login')) {
      await new Promise(r => setTimeout(r, 2000));
      if (Date.now() - startTime > 5 * 60 * 1000) {
        log('登录超时');
        await browser.close();
        return;
      }

