      const actionHint = e.actionHint || '';
      const conf = e.confidence === 'uncertain' ? ' ⚠️' : '';
      return '<div class="client-row"><span>' + esc(e.name) + conf + ' <span class="from-tag">' + esc(grade) + '级</span></span><span style="font-size:10px;color:var(--text-secondary);">' + esc(reason || actionHint).substring(0, 30) + '</span></div>';
    }).join('');
    return '<div class="terminal-pool" style="' + style + '"><h4>' + icon + ' ' + t + ' — ' + items.length + '人</h4>' + itemsHtml + '<div style="font-size:10px;color:var(--text-secondary);margin-top:6px;">' + tip + '</div></div>';
  }).filter(Boolean).join('');

  // 构建 JSON 数据（供弹窗用）
  function toEntry(e) {
    return {
      n: e.name, c: e.countryCN || e.country || '??',
      d: typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays : 999,
      g: e.grade || '?',
      st: e.stage || '需求探索',
      ac: e.actionHint || '',
      pr: e.priority || 'idle',
      cf: e.confidence || 'certain',
      rs: e.reason || ''
    };
  }
  function kpiSort(arr) {
    const order = { now: 0, soon: 1, idle: 2 };
    return arr.sort((a, b) => {
      const pd = (order[a.pr] ?? 3) - (order[b.pr] ?? 3);
      if (pd !== 0) return pd;
      return a.d - b.d;
    });
  }

  const matrixJson = {};
  for (const s of stageOrder) {
    matrixJson[s] = {};
    for (const g of gradeOrder) {
      matrixJson[s][g] = kpiSort((matrixData[s][g] || []).map(toEntry));
    }
  }
  // 终态也加入 JSON
  for (const t of terminalStages) {
