function extractConversationSnippet(msgs, N) {
  if (!msgs || msgs.length === 0) return [];
  const real = [];
  for (const m of [...msgs].reverse()) {
    if (isSys((m.message || m).content)) continue;
    const msg = m.message || m;
    const uid = msg.sender && msg.sender.uid || '';
    const text = getText(msg.content, msg.searchableContent);
    if (!text.trim()) continue;
    const date = msg.createAt ? new Date(msg.createAt).toISOString().slice(0, 10) : '?';
    const who = uid === OUR_UID ? '[我方]' : '[客户]';
    real.push(who + ' ' + date + ' | ' + text.substring(0, 200));
    if (real.length >= N) break;
  }
  return real.reverse();
}

function computeDirection(customerMsgs, ourMsgs, lastCustomerMsgDate) {
  if (lastCustomerMsgDate) {
    const lastCustTs = new Date(lastCustomerMsgDate).getTime();
    let lastOurTs = 0;
    // 从已遍历的消息中拿 lastOurDate（在循环里记的）
    return 'to_them'; // 默认，主循环会覆盖
  }
  if (customerMsgs > ourMsgs) return 'to_us';
  return 'to_them';
}

function matchOrder(name, ordersData) {
  if (!ordersData || !ordersData.orders || ordersData.orders.length === 0) return null;
  if (!name) return null;
  const n = name.toLowerCase().trim();
  // 精确匹配
  for (const o of ordersData.orders) {
    if ((o.customer || '').toLowerCase().trim() === n) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
  }
  // 模糊匹配：客户名包含公司名或反之
  for (const o of ordersData.orders) {
    const cn = (o.customer || '').toLowerCase().trim();
    if (!cn) continue;
    if (n.includes(cn) || cn.includes(n)) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
  }
  return null;
}

function bucketFilter(client) {
  const d = client.lastCustomerMsgDays;
  const g = client.grade;
  const hasOrder = !!client.orderMatched;
  const msgCount = client.realMsgs || 0;
  // 桶 2：有任一活跃信号
  if (typeof d === 'number' && d < 60) return 2;
  if (g === 'A' || g === 'S') return 2;
  if (hasOrder) return 2;
  if (msgCount >= 10) return 2;
  // 其余 → 桶 1
  return 1;
}

