// 提取当前页订单数据
function extractPageOrders() {
  return page.evaluate(() => {
    const result = [];
    const rows = document.querySelectorAll('.vue-recycle-scroller__item-view');
    rows.forEach(row => {
      // 跳过表头行
      const rowItem = row.querySelector('.row-item');
      if (rowItem && rowItem.classList.contains('row-item__hidden_border_top')) return;
      const cells = row.querySelectorAll('.cell-inner');
      if (cells.length < 8) return;
      const texts = Array.from(cells).map(c => c.textContent?.trim() || '');
      // DOM实测: [0]checkbox空 [1]保障图标空 [2]订单号前半 [3]订单号后半 [4]日期 [5]金额 [6]客户 [7]状态 [8]ERP [9]空 [10]空
      const orderNo = (texts[2] || '') + (texts[3] || '');
      if (orderNo.length >= 15 && /^\d{15,}$/.test(orderNo)) {
        result.push({
          orderNo: orderNo,
          orderDate: texts[4],
          amount: texts[5],
          customer: texts[6],
          status: texts[7],
          erpStatus: texts[8] || '',
        });
      }
    });
    return result;
  });
}

