398	    const wsState = await evalInIframe(cdpClient, iframeSessionId, 10,
399	      `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
400	    );
401	    log(`WS 状态: ${JSON.stringify(wsState)}`);
402	
403	    if (!wsState?.ws) {
404	      log('等待 WebSocket 连接...');
405	      await sleep(15000);
406	      const wsState2 = await evalInIframe(cdpClient, iframeSessionId, 11,
407	        `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
408	      );
409	      log(`WS 状态(重试): ${JSON.stringify(wsState2)}`);
410	    }
411	
412	    // 拉取消息
413	    let pulled = 0;
414	    let errors = 0;
415	    let totalNewMsgs = 0;
416	    let msgIdCounter = 100;
417	
418	    for (let i = 0; i < changed.length; i++) {
419	      const conv = changed[i];
420	      try {
421	        const allMessages = [];
422	        let cursor = 9007199254740991;
423	        let pageNum = 0;
424	
425	        while (pageNum < MAX_PAGES) {
426	          const msgId = msgIdCounter++;
427	          const raw = await evalInIframe(cdpClient, iframeSessionId, msgId,
428	            `(async function() {
429	              try {
430	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${conv.cid}', false, ${cursor}, ${MSG_COUNT}, false]);
431	                return JSON.stringify(result);
432	              } catch(e) {
433	                return JSON.stringify({ __error: e.message });
434	              }
435	            })()`,
436	            true
437	          );
438	
439	          await sleep(1500);
440	
441	          if (!raw || raw.__error) {
442	            if (raw?.__error === 'timeout') { log(`  [${conv.name}] LWP超时`); }
443	            break;
444	          }
445	
446	          let response;
447	          try { response = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { break; }
448	          if (response.code !== 200) break;
449	
450	          const body = response.body;
451	          if (!body?.userMessageModels || body.userMessageModels.length === 0) break;
452	
453	          allMessages.push(...body.userMessageModels);
454	
455	          if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
456	          cursor = body.nextCursor;
457	          pageNum++;
458	        }
459	
460	        // 保存
461	        const safeName = sanitizeFilename(conv.cid);
462	        const output = {
463	          cid: conv.cid,
464	          name: conv.name,
465	          fetchedAt: new Date().toISOString(),
466	          totalMessages: allMessages.length,
467	          messages: allMessages,
468	        };
469	        fs.writeFileSync(path.join(CHAT_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
470	        pulled++;
471	        totalNewMsgs += allMessages.length;
472	        if (allMessages.length > 0) {
473	          log(`  [${i+1}/${changed.length}] ${conv.name}: ${allMessages.length} 条消息`);
474	        }
475	      } catch (e) {
476	        errors++;
477	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
478	      }
479	    }
480	
481	    log(`拉取完成: ${pulled} 个会话, ${totalNewMsgs} 条消息, ${errors} 个错误`);
482	  } else {
483	    log('跳过 LWP 拉取（无 CDP/iframe 访问）');
484	    log('已保存元数据差异。在新对话中可通过 STATE.md 了解哪些客户需要深抓。');
485	  }
486	
487	  // ---- Step 9: 预计算 + 输出摘要 ----
488	  computePreComputed(convList);
489	  printSummary(convList, changed);
490	  log('同步完成。浏览器保持打开，供后续脚本使用');
491	}
492	
493	// ===================== LWP 工具 =====================
494	
495	async function installLwp(cdpClient, iframeSessionId) {
496	  const expr = `
497	    (function() {
498	      var _send = WebSocket.prototype.send;
499	      var _ae = WebSocket.prototype.addEventListener;
500	
501	      window.__lwpPending = {};
502	      window.__lwpSeq = 0;
503	
504	      WebSocket.prototype.send = function(data) {
505	        if (!window.__lwpWs && this.readyState === 1) {
506	          window.__lwpWs = this;
507	          _ae.call(this, 'message', function(event) {
508	            try {
509	              var raw = typeof event.data === 'string' ? event.data : '';
510	              if (raw.indexOf('"code"') < 0) return;
511	              var parsed = JSON.parse(raw);
512	              var mid = parsed.headers && parsed.headers.mid;
513	              if (mid && window.__lwpPending[mid]) {
514	                var p = window.__lwpPending[mid];
515	                delete window.__lwpPending[mid];
516	                p.resolve(parsed);
517	              }
518	            } catch(e) {}
519	          });
520	          console.log('[LWP] WS captured: ' + this.url);
521	        }
522	        return _send.call(this, data);
523	      };
524	
525	      window.__lwpRequest = function(lwpPath, body) {
526	        return new Promise(function(resolve, reject) {
527	          var ws = window.__lwpWs;
528	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
529	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
530	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
531	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
532	          ws.send(req);
533	          setTimeout(function() {
534	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
535	          }, 30000);
536	        });
537	      };
538	
539	      return JSON.stringify({ installed: true });
540	    })()
541	  `;
542	
543	  return sendToTarget(cdpClient, iframeSessionId, 3, expr);
544	}
545	
546	async function evalInIframe(cdpClient, iframeSessionId, id, expression, awaitPromise) {
547	  const raw = await sendToTarget(cdpClient, iframeSessionId, id, expression, awaitPromise);
548	  if (!raw) return raw;
549	  try { return JSON.parse(raw); } catch (e) { return raw; }
550	}
551	
552	async function sendToTarget(cdpClient, sessionId, id, expression, awaitPromise) {
553	  return new Promise((resolve) => {
554	    const timeout = setTimeout(() => resolve(null), 35000);
555	
556	    const handler = (msg) => {
557	      if (sessionId && msg.sessionId !== sessionId) return;
558	      try {
559	        const m = JSON.parse(msg.message);
560	        if (m.id === id) {
561	          clearTimeout(timeout);
562	          cdpClient.off('Target.receivedMessageFromTarget', handler);
563	          if (m.result?.result?.value !== null && m.result?.result?.value !== undefined) {
564	            resolve(m.result.result.value);
565	          } else if (m.result) {
566	            resolve(m.result);
567	          } else {
568	            resolve(null);
569	          }
570	        }
571	      } catch (e) { clearTimeout(timeout); resolve(null); }
572	    };
573	
574	    cdpClient.on('Target.receivedMessageFromTarget', handler);
575	
576	    cdpClient.send('Target.sendMessageToTarget', {
577	      sessionId: sessionId || cdpClient._sessionId,
578	      message: JSON.stringify({
579	        id,
580	        method: 'Runtime.evaluate',
581	        params: { expression, awaitPromise: !!awaitPromise, returnByValue: true }
582	      })
583	    }).catch(() => { clearTimeout(timeout); resolve(null); });
584	  });
585	}
586	
587	// ===================== 预计算 =====================
588	
589	const SYSTEM_MSG_PATTERNS = [
590	  '自动接待将不再触发',
591	  'Since you have read the conversation',
592	  'Marco大模型翻译',
593	  '阿里国际Marco大模型翻译',
594	  '买家有流失风险',
595	  'Buyer has churn risk',
596	  '一旦离开平台发生纠纷或欺诈',
597	  '由于您介入该会话',
598	  'Due to your intervention in this session',
599	  'AI给您生成了一条回复建议',
600	  'You have a visitor',
601	  'This buyer has been pre-screened',
602	];
603	
604	function computePreComputed(convList) {
605	  const now = Date.now();
606	  const chatDir = path.join(DATA_DIR, 'chat_history');
607	
608	  for (const c of convList) {
609	    c.preComputed = {};
610	
611	    // 1. 是否未读
612	    c.preComputed.isUnread = (c.unreadCount || 0) > 0;
613	
614	    // 2. 距上次联系天数
615	    const lct = c.lastContactTimeLong || c.lastContactTime || 0;
616	    c.preComputed.daysSinceLastContact = lct > 0 ? Math.floor((now - lct) / 86400000) : null;
617	
618	    // 3. latestMessage 是否是系统消息
619	    const lmContent = c.latestMessage?.content || '';
620	    c.preComputed.isLatestMessageSystem = false;
621	    if (lmContent) {
622	      for (const pat of SYSTEM_MSG_PATTERNS) {
623	        if (lmContent.includes(pat)) {
624	          c.preComputed.isLatestMessageSystem = true;
625	          break;
626	        }
627	      }
628	    }
629	
630	    // 4. 是否有 chat_history 文件
631	    const fileName = sanitizeFilename(c.cid) + '.json';
632	    const filePath = path.join(chatDir, fileName);
633	    c.preComputed.hasChatHistoryFile = fs.existsSync(filePath);
634	
635	    // 5. 是否有真实消息（chat_history 文件中存在非系统消息）
636	    c.preComputed.hasRealMessages = false;
637	    if (c.preComputed.hasChatHistoryFile) {
638	      try {
639	        const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
640	        for (const msg of (data.messages || [])) {
641	          const content = msg.message?.content?.text?.content || '';
642	          if (!content) continue;
643	          let isSys = false;
644	          for (const pat of SYSTEM_MSG_PATTERNS) {
645	            if (content.includes(pat)) { isSys = true; break; }
646	          }
647	          if (!isSys) {
648	            c.preComputed.hasRealMessages = true;
649	            break;
650	          }
651	        }
652	      } catch (e) {}
653	    }
654	  }
655	
656	  // 重新保存带 preComputed 的元数据
657	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
658	  const latestMeta = {
659	    exportedAt: new Date().toISOString(),
660	    total: convList.length,
661	    conversations: convList,
662	  };
663	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
664	  log(`preComputed 已计算，元数据已更新`);
665	}
666	
667	function printSummary(convData, changed) {
668	  // 统计（基于原始消息数据，不依赖 latestMessage）
669	  const now = Date.now();
670	  const last24h = convData.filter(c => (c.lastContactTime || 0) > now - 86400000).length;
671	
672	  // 从 chat_history 文件统计客户回复（不是从 latestMessage）
673	  let totalCustomerMsgs = 0;
674	  let totalOurMsgs = 0;
675	  let customersReplied = new Set();
676	  const CUTOFF = now - 7 * 86400000;
677	
678	  const chatDir = path.join(DATA_DIR, 'chat_history');
679	  if (fs.existsSync(chatDir)) {
680	    const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json') && f !== '_summary.json');
681	    for (const file of files) {
682	      try {
683	        const data = JSON.parse(fs.readFileSync(path.join(chatDir, file), 'utf-8'));
684	        for (const msg of (data.messages || [])) {
685	          const ts = msg.message?.createAt || 0;
686	          if (ts < CUTOFF) continue;
687	          const sender = msg.message?.sender?.uid || '';
688	          const content = msg.message?.content?.text?.content || '';
689	          if (!content) continue;
690	          if (sender === '2500000853693@icbu') {
691	            totalOurMsgs++;
692	          } else {
693	            totalCustomerMsgs++;
694	            customersReplied.add(data.cid || file);
695	          }
696	        }
697	      } catch (e) {}
698	    }
699	  }
700	
701	  log('');
702	  log('========== 同步摘要 ==========');
703	  log(`总会话: ${convData.length}`);
704	  log(`变化会话: ${changed.length}`);
705	  log(`24h内有 activity: ${last24h}`);
706	  log('');
707	  log(`近7天消息 (来自 chat_history 实测):`);
708	  log(`  客户回复: ${totalCustomerMsgs} 条 / ${customersReplied.size} 人`);
709	  log(`  我方发送: ${totalOurMsgs} 条`);
710	  log(`数据已保存到 data/ 目录`);
711	  log('==============================');
712	}
713	
714	// ===================== 启动 =====================
715	
716	main().catch(err => {
717	  log(`致命错误: ${err.message}`);
718	  console.error(err);
719	  process.exit(1);
720	});
