const fs = require('fs');
const path = require('path');

const meta = JSON.parse(fs.readFileSync('data/tm_conversations_latest.json', 'utf8'));
const chatDir = 'data/chat_history';
const chatFiles = new Set(fs.readdirSync(chatDir).filter(f => f.endsWith('.json') && f !== '_summary.json'));

// sanitize cid same way as sync script
function sanitize(cid) {
  return cid.replace(/[<>:\"/\\\\|?*#@]/g, '_').substring(0, 200);
}

const missing = [];
const hasChat = [];
for (const c of meta.conversations) {
  const fname = sanitize(c.cid) + '.json';
  if (chatFiles.has(fname)) {
    hasChat.push(c);
  } else {
    missing.push(c);
  }
}

console.log('总会话:', meta.conversations.length);
console.log('有 chat_history:', hasChat.length);
console.log('缺 chat_history:', missing.length);
console.log('');

if (missing.length > 0) {
  console.log('=== 缺 chat_history 的客户 ===');
  missing.slice(0, 30).forEach(c => {
    const days = c.lastContactTimeLong 
      ? Math.floor((Date.now() - c.lastContactTimeLong) / 86400000) + 'd'
      : '?';
    const unread = (c.unreadCount || 0) > 0 ? '🔴' : '';
    console.log('  ' + unread + ' ' + (c.name || '?').padEnd(30) + ' | ' + (c.companyName || '').substring(0,20).padEnd(20) + ' | 最后联系: '+days);
  });
}

// 检查 chat_history 中哪些是新创建的（今天）
console.log('');
const today = new Date();
const newToday = [];
for (const f of chatFiles) {
  const stat = fs.statSync(path.join(chatDir, f));
  if (stat.mtime > new Date(today.getFullYear(), today.getMonth(), today.getDate())) {
    newToday.push(f);
  }
}
console.log('今天更新的 chat_history: ' + newToday.length + ' 个');
newToday.forEach(f => {
  try {
    const d = JSON.parse(fs.readFileSync(path.join(chatDir, f), 'utf8'));
    console.log('  ' + (d.name || f).padEnd(30) + ' | ' + d.totalMessages + ' 条');
  } catch(e) {}
});
