  // 模糊匹配：客户名包含公司名或反之
  for (const o of ordersData.orders) {
    const cn = (o.customer || '').toLowerCase().trim();
    if (!cn) continue;
    if (n.includes(cn) || cn.includes(n)) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
  }
  return null;
}

