          customerMsgs++;
          if (date > latestCustDate) latestCustDate = date;
          if (text.trim()) { fullCustText += text + ' | '; fullConvText += text + ' | '; }
          if (date) lastCustomerMsgDays = Math.min(lastCustomerMsgDays, Math.floor((NOW - new Date(date).getTime()) / DAY));
        }
      }
    } catch (e) { /* skip corrupt */ }
  }

  const realMsgs = customerMsgs + ourMsgs;
  const country = c.country || '';
  const direction = lastCustomerMsgDays !== 9999 && latestCustDate > latestOurDate ? 'to_us' : 'to_them';

  // 质量等级（脚本继续算，AI 可覆盖）
  const ql = determineQuality({
    realMsgs, customerMsgs, ourMsgs, hasPrice: false, hasSample: false, hasQuantity: false, lastCustomerMsgDays
  }, fullCustText, fullConvText);

  // 订单匹配
  const orderMatched = matchOrder(c.name, ordersData);

  // 对话片段
  const snippet = extractConversationSnippet(allMsgs, 12);

  const obj = {
    name: c.name || '(未知)',
    country,
    countryCN: countryCN(country),
    cid: c.cid,
    grade: ql.grade,
    gradeReason: ql.reason,
    totalMsgs: msgCount,
    customerMsgs,
    ourMsgs,
    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
    direction,
    order: orderMatched,
    snippet,
    // 临时字段（供分桶+后续使用）
    realMsgs,
    fullCustText,
    fullConvText,
  };

  obj.bucket = bucketFilter(obj);
  enhanced.push(obj);
}

