'  .terminal-pool .from-tag { font-size: 10px; color: var(--text-secondary); background: var(--bg-tertiary); padding: 1px 6px; border-radius: 10px; margin-left: 4px; }\n' +
'  .terminal-pool .client-row { font-size: 11px; padding: 3px 0; display: flex; justify-content: space-between; border-bottom: 1px dotted var(--border); }\n' +
'  .terminal-pool .client-row:last-child { border-bottom: none; }\n' +
'  .footer { margin-top: 24px; padding: 14px; border-top: 1px solid var(--border); font-size: 11px; color: var(--text-secondary); text-align: center; }\n' +
