'  .modal-overlay.show { display:flex; }\n' +
'  .modal-box { background:var(--bg-secondary); border-radius:10px; width:750px; max-width:92vw; max-height:75vh; overflow-y:auto; box-shadow:0 8px 30px rgba(0,0,0,0.25); }\n' +
