const fs = require('fs');
const meta = JSON.parse(fs.readFileSync('data/tm_conversations_latest.json','utf8'));
const chatDir = 'data/chat_history';
const existingFiles = new Set(fs.readdirSync(chatDir).filter(f => f.endsWith('.json')));

// enhanced_classify.js 的方式: 只替换 # @ 
function classifySanitize(cid) { return cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : ''; }
// sync_okki.js 的方式: 替换多种字符
function syncSanitize(cid) { return cid.replace(/[<>:\"/\\\\|?*#@]/g, '_').substring(0, 200) + '.json'; }

let classifyMatch = 0, classifyMiss = 0;
let syncMatch = 0, syncMiss = 0;
const classifyMissSamples = [];
const syncMissSamples = [];

for (const c of meta.conversations.slice(0, 50)) {
  const cf = classifySanitize(c.cid);
  const sf = syncSanitize(c.cid);
  if (existingFiles.has(cf)) classifyMatch++; else { classifyMiss++; if (classifyMissSamples.length < 3) classifyMissSamples.push({name:c.name, cid:c.cid, expected:cf}); }
  if (existingFiles.has(sf)) syncMatch++; else { syncMiss++; if (syncMissSamples.length < 3) syncMissSamples.push({name:c.name, cid:c.cid, expected:sf}); }
}

console.log('前50个测试:');
console.log('classifySanitize: 命中=' + classifyMatch + ', 未命中=' + classifyMiss);
console.log('syncSanitize:    命中=' + syncMatch + ', 未命中=' + syncMiss);
console.log('');
if (classifyMissSamples.length > 0) {
  console.log('classify 未命中示例:');
  classifyMissSamples.forEach(s => console.log('  ' + s.name + ' | ' + s.expected));
}
if (syncMissSamples.length > 0) {
  console.log('sync 未命中示例:');
  syncMissSamples.forEach(s => console.log('  ' + s.name + ' | ' + s.expected));
}

// Also check: do the two sanitizers produce different results?
console.log('');
let diffCount = 0;
for (const c of meta.conversations) {
  if (classifySanitize(c.cid) !== syncSanitize(c.cid)) diffCount++;
}
console.log('两种sanitize结果不同的cid: ' + diffCount + '/' + meta.conversations.length);
