const afterSalesPatterns = [
  'quality issue', 'defect', 'damaged', 'complaint', 'wrong item',
  '质量问题', '破损', '投诉', '退换', '退款', 'refund',
  'not as described', 'missing', 'stain', 'torn', 'broken',
  'problème', 'défaut', 'remboursement',
];
const isAfterSales = afterSalesPatterns.some(p => lastCustMsgs.includes(p) || lastOurMsgs.includes(p));
if (isAfterSales && silence < 30) return { stage: '售后', reason: '对话含质量/投诉信号' };

// 已签收
const deliveredPatterns = ['received', 'delivered', 'arrived', '收到', '已收', 'reçu', 'livré'];
const isDelivered = deliveredPatterns.some(p => lastCustMsgs.includes(p));
if (isDelivered && silence < 60) return { stage: '已签收', reason: '客户确认收货' };

// 已发货/在途
const shippedPatterns = [
  'shipped', 'tracking', 'logistics', 'on the way', 'in transit',
  '已发货', '物流', '在途', '运输中', '船期', '航班',
  'tracking number', 'container', 'vessel', 'eta',
  'expédié', 'suivi', 'en transit',
];
const isShipped = shippedPatterns.some(p => lastOurMsgs.includes(p) || lastCustMsgs.includes(p));
if (isShipped && silence < 30) return { stage: '已发货/在途', reason: '对话含物流/发货信号' };

// 待付款（PI已发、等付款）
const pendingPaymentPatterns = [
  'pi sent', 'proforma', 'invoice sent', 'make payment', 'deposit',
  'PI已发', '付款', '定金', '打款', 'invoice', 'tt ',
  'waiting for payment', 'bank transfer', 'swift',
  'facture', 'paiement', 'acompte',
];
const isPendingPayment = pendingPaymentPatterns.some(p => lastOurMsgs.includes(p) || lastMsgs.includes(p));
if (isPendingPayment && silence < 30) return { stage: '待付款', reason: 'PI已发/等待付款' };

// 谈判中（价格/数量/规格来回沟通）
const negotiationPatterns = [
  'discount', 'cheaper', 'price', 'negotiate', 'best offer',
  '折扣', '便宜', '价格', '报价', '最低', '数量', '规格',
  'réduction', 'remise', 'prix', 'négocier',
];

