/**
 * 规则引擎：从 s2 生成 s3_ai_judgments.json
 * 基于 classification-rules.md 的阶段定义 + snippet 文本分析
 *
 * 用法：node scripts/gen_s3_rules.js
 */

const fs = require('fs');
const path = require('path');

const s2Path = path.join(__dirname, '..', 'data', 's2_ai_input.json');
const s3Path = path.join(__dirname, '..', 'data', 's3_ai_judgments.json');

const s2 = JSON.parse(fs.readFileSync(s2Path, 'utf8'));
console.log(`读取 s2: ${s2.length} 条`);

function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }

// ── 阶段判定（基于 snippet 文本规则）──
function determineStage(entry) {
  const snippets = entry.snippet || [];
  const allText = snippets.join('\n').toLowerCase();
  const lastMsgs = snippets.slice(-6).join('\n').toLowerCase(); // 最近6条
  const lastCustMsgs = snippets.filter(s => s.startsWith('[客户]')).slice(-3).join('\n').toLowerCase();
  const lastOurMsgs = snippets.filter(s => s.startsWith('[我方]')).slice(-3).join('\n').toLowerCase();

  const silence = entry.lastCustomerMsgDays;

  // 终态：未成交（客户明确拒绝）
  const rejectionPatterns = [
    'not interested', 'found another', 'went with', 'too expensive',
    '不再需要', '已经找到', '价格太高', '不感兴趣', '取消订单',
    'cancel', 'sorry we', 'won\'t be proceeding', 'decided not to',
    'pas intéressé', 'trop cher', 'annuler',
  ];
  const rejected = rejectionPatterns.some(p => lastCustMsgs.includes(p));
  if (rejected && silence > 14) return { stage: '未成交', reason: '客户明确拒绝/放弃' };

  // 客户表达满意/喜欢 → 已签收信号
  const satisfactionPatterns = [
    'me encant', 'me gust', 'muy bonito', 'precioso', 'volvería a pedir',
    'i love', 'very nice', 'beautiful', 'amazing', 'great quality',
    '我很喜欢', '很满意', '不错', '挺好的', '非常好',
    'excellent', 'parfait', 'magnifique', 'très bien',
    'thank you so much', 'muchas gracias',
  ];
  const isSatisfied = satisfactionPatterns.some(p => lastCustMsgs.includes(p));

  // 已签收 — 优先级高（客户确认收货 或 表达满意）
  const deliveredPatterns = ['received', 'delivered', 'arrived', '收到', '已收', 'reçu', 'livré', 'recibido'];
  const isDelivered = deliveredPatterns.some(p => lastCustMsgs.includes(p));
  if ((isDelivered || isSatisfied) && silence < 90) return { stage: '已签收', reason: isDelivered ? '客户确认收货' : '客户表达满意' };

  // 已发货/在途（物流信号，但必须先确认不是已签收）
  const shippedPatterns = [
    'shipped', 'tracking', 'logistics', 'on the way', 'in transit',
    '已发货', '物流', '在途', '运输中', '船期', '航班',
    'tracking number', 'container', 'vessel', 'eta',
    'expédié', 'suivi', 'en transit', 'envío', 'entrega',
    'enviamos', 'enviado', 'número de rastreo', 'número de seguimiento',
  ];
  const isShipped = shippedPatterns.some(p => lastOurMsgs.includes(p) || lastCustMsgs.includes(p));
  if (isShipped && silence < 60) return { stage: '已发货/在途', reason: '对话含物流/发货信号' };

  // 售后 — 只扫客户消息，且客户没有表达满意
  const afterSalesPatterns = [
    'quality issue', 'defect', 'damaged', 'wrong item',
    '质量问题', '破损', '退换', '退款', 'refund',
    'not as described', 'stain', 'torn', 'broken',
    'défaut', 'remboursement', 'defectuoso', 'dañado',
    'mala calidad', 'roto', 'manchado',
  ];
  const isAfterSales = afterSalesPatterns.some(p => lastCustMsgs.includes(p));
  if (isAfterSales && !isSatisfied && silence < 30) return { stage: '售后', reason: '客户反馈质量问题' };

  // 待付款（PI已发、等付款）
  const pendingPaymentPatterns = [
    'pi sent', 'proforma', 'invoice sent', 'make payment', 'deposit',
    'PI已发', '付款', '定金', '打款', 'invoice', 'tt ',
    'waiting for payment', 'bank transfer', 'swift',
    'facture', 'paiement', 'acompte',
  ];
  const isPendingPayment = pendingPaymentPatterns.some(p => lastOurMsgs.includes(p) || lastMsgs.includes(p));
  if (isPendingPayment && silence < 30) return { stage: '待付款', reason: 'PI已发/等待付款' };

  // 谈判中（价格/数量/规格来回沟通）
  const negotiationPatterns = [
    'discount', 'cheaper', 'price', 'negotiate', 'best offer',
    '折扣', '便宜', '价格', '报价', '最低', '数量', '规格',
